/**
 * External dependencies
 */
import { useKeyDownEffect } from '@googleforcreators/design-system';

function useKeyDeleteStop(ref, onDelete) {
  useKeyDownEffect(
    ref,
    'delete',
    () => {
      ref.current.focus();
      onDelete();
    },
    [onDelete, ref]
  );
}

export default useKeyDeleteStop;
